import{_ as a,o as i,c as t,ag as o}from"./chunks/framework.BDReElpY.js";const g=JSON.parse('{"title":"Versioning and Stability","description":"","frontmatter":{},"headers":[],"relativePath":"guide/versioning.md","filePath":"guide/versioning.md"}'),n={name:"guide/versioning.md"};function r(d,e,s,l,c,h){return i(),t("div",null,[...e[0]||(e[0]=[o(`<h1 id="versioning-and-stability" tabindex="-1">Versioning and Stability <a class="header-anchor" href="#versioning-and-stability" aria-label="Permalink to &quot;Versioning and Stability&quot;">​</a></h1><p>This page describes Vex&#39;s versioning policy, stability guarantees, and migration expectations.</p><h2 id="semantic-versioning" tabindex="-1">Semantic Versioning <a class="header-anchor" href="#semantic-versioning" aria-label="Permalink to &quot;Semantic Versioning&quot;">​</a></h2><p>Vex follows <strong>Semantic Versioning 2.0.0</strong> (<code>MAJOR.MINOR.PATCH</code>):</p><table tabindex="0"><thead><tr><th>Change</th><th>Version Bump</th><th>Examples</th></tr></thead><tbody><tr><td>Bug fixes (backward-compatible)</td><td>PATCH (0.1.0 -&gt; 0.1.1)</td><td>Fix crash in parser, correct codegen for edge case</td></tr><tr><td>New features (backward-compatible)</td><td>MINOR (0.1.0 -&gt; 0.2.0)</td><td>New stdlib module, new contract, new compiler flag</td></tr><tr><td>Breaking changes</td><td>MAJOR (0.1.0 -&gt; 1.0.0)</td><td>Syntax change, removed API, changed behavior</td></tr></tbody></table><p><strong>Current version: 0.1.2</strong> -- Vex is pre-1.0. Breaking changes may occur in minor versions during 0.x.</p><h2 id="stability-tiers" tabindex="-1">Stability Tiers <a class="header-anchor" href="#stability-tiers" aria-label="Permalink to &quot;Stability Tiers&quot;">​</a></h2><h3 id="tier-1-stable" tabindex="-1">Tier 1: Stable <a class="header-anchor" href="#tier-1-stable" aria-label="Permalink to &quot;Tier 1: Stable&quot;">​</a></h3><p>These are guaranteed NOT to change without a major version bump (after 1.0):</p><ul><li>Core syntax (<code>fn</code>, <code>let</code>, <code>struct</code>, <code>enum</code>, <code>match</code>, <code>if</code>, <code>for</code>, <code>while</code>, <code>loop</code>)</li><li>Primitive types (<code>i32</code>, <code>f64</code>, <code>bool</code>, <code>char</code>, etc.)</li><li>Basic operator semantics (<code>+</code>, <code>-</code>, <code>*</code>, <code>/</code>, <code>==</code>, <code>!=</code>, <code>&lt;</code>, <code>&gt;</code>)</li><li>Standard prelude types: <code>Option&lt;T&gt;</code>, <code>Result&lt;T,E&gt;</code>, <code>Box&lt;T&gt;</code>, <code>Vec&lt;T&gt;</code>, <code>Map&lt;K,V&gt;</code>, <code>Set&lt;T&gt;</code></li><li>Core contracts: <code>$Add</code>, <code>$Sub</code>, <code>$Mul</code>, <code>$Div</code>, <code>$Eq</code>, <code>$Ord</code>, <code>$Display</code>, <code>$Debug</code>, <code>$Clone</code>, <code>$Drop</code></li><li><code>vex run</code> and <code>vex compile</code> CLI</li></ul><h3 id="tier-2-stabilizing-0-x" tabindex="-1">Tier 2: Stabilizing (0.x) <a class="header-anchor" href="#tier-2-stabilizing-0-x" aria-label="Permalink to &quot;Tier 2: Stabilizing (0.x)&quot;">​</a></h3><p>These are largely stable but may see minor adjustments:</p><ul><li><code>Channel&lt;T&gt;</code>, <code>Ptr&lt;T&gt;</code>, <code>Span&lt;T&gt;</code>, <code>RawBuf</code></li><li><code>async fn</code> / <code>await</code> semantics</li><li><code>go</code> blocks</li><li>Pattern matching (all pattern forms)</li><li>Operator overloading (<code>$Index</code>, <code>$BitAnd</code>, etc.)</li><li><code>vex fmt</code>, <code>vex test</code>, <code>vex doc</code></li><li>Standard library modules: <code>http</code>, <code>serde</code>, <code>crypto</code>, <code>fs</code>, <code>io</code>, <code>time</code></li></ul><h3 id="tier-3-experimental" tabindex="-1">Tier 3: Experimental <a class="header-anchor" href="#tier-3-experimental" aria-label="Permalink to &quot;Tier 3: Experimental&quot;">​</a></h3><p>These are under active development and may change significantly:</p><ul><li><code>graph fn</code> GPU kernels</li><li>SIR pipeline and all GPU backends</li><li><code>Complex&lt;T&gt;</code>, <code>OrderedMap&lt;K,V&gt;</code></li><li>SIMD operation set (saturating, FMA, CLMUL, reductions)</li><li><code>vex fuzz</code>, <code>vex bench</code></li><li>Package manager registry protocol</li><li><code>comptime</code> advanced features (reflection, codegen)</li><li>WASM target</li><li>Windows and FreeBSD support</li><li>OpenVINO, CoreML, OpenCL backends</li></ul><h3 id="tier-4-internal-unstable" tabindex="-1">Tier 4: Internal / Unstable <a class="header-anchor" href="#tier-4-internal-unstable" aria-label="Permalink to &quot;Tier 4: Internal / Unstable&quot;">​</a></h3><p>These are compiler internals NOT intended for direct use:</p><ul><li><code>#</code>-prefixed compiler intrinsics (may change without notice)</li><li>Runtime C API (<code>vumm.c</code> functions)</li><li>SIR internal graph representation</li><li>LSP protocol extensions</li></ul><h2 id="deprecation-process" tabindex="-1">Deprecation Process <a class="header-anchor" href="#deprecation-process" aria-label="Permalink to &quot;Deprecation Process&quot;">​</a></h2><p>When an API is scheduled for removal:</p><ol><li><strong>Deprecation notice</strong> -- Added to documentation and release notes (MINOR release)</li><li><strong>Deprecation warning</strong> -- Compiler emits warning on use (next MINOR release)</li><li><strong>Removal</strong> -- API removed (next MAJOR release, or after 2 minor releases during 0.x)</li></ol><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// Example deprecation flow:</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// v0.2.0: oldFunction() documented as deprecated</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// v0.3.0: #[deprecated(&quot;use newFunction() instead&quot;)] warning emitted</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// v0.4.0: oldFunction() removed</span></span></code></pre></div><h3 id="deprecation-attribute" tabindex="-1">Deprecation Attribute <a class="header-anchor" href="#deprecation-attribute" aria-label="Permalink to &quot;Deprecation Attribute&quot;">​</a></h3><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">#[deprecated(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;Use newMethod() instead&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)]</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">fn</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> oldMethod</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">() { </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">...</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> }</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">#[deprecated(since </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;0.2.0&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, note </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;Use processAsync()&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)]</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">fn</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> processSync</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">() { </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">...</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> }</span></span></code></pre></div><h2 id="migration-guide-v0-1-x-to-v0-2-x" tabindex="-1">Migration Guide: v0.1.x to v0.2.x <a class="header-anchor" href="#migration-guide-v0-1-x-to-v0-2-x" aria-label="Permalink to &quot;Migration Guide: v0.1.x to v0.2.x&quot;">​</a></h2><h3 id="syntax-changes" tabindex="-1">Syntax Changes <a class="header-anchor" href="#syntax-changes" aria-label="Permalink to &quot;Syntax Changes&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Old (v0.1.x)</th><th>New (v0.2.x)</th><th>Reason</th></tr></thead><tbody><tr><td><code>impl Contract for Type</code></td><td>Contract on struct: <code>struct T: Contract</code></td><td>Vex doesn&#39;t use <code>impl</code> keyword</td></tr><tr><td><code>::</code> for method calls</td><td><code>.</code> for ALL member access</td><td>Unified access syntax</td></tr><tr><td><code>mut</code> keyword</td><td><code>!</code> suffix (<code>let!</code>, <code>&amp;T!</code>)</td><td>Consistent with type system</td></tr></tbody></table><h3 id="api-changes" tabindex="-1">API Changes <a class="header-anchor" href="#api-changes" aria-label="Permalink to &quot;API Changes&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Old</th><th>New</th></tr></thead><tbody><tr><td><code>Option.unwrap()</code></td><td><code>Option.unwrap()</code> (unchanged, but <code>.expect()</code> added)</td></tr><tr><td><code>Vec.push()</code> returning bool</td><td><code>Vec.push()</code> returning void (use <code>.tryPush()</code> for fallible)</td></tr></tbody></table><h3 id="runtime-changes" tabindex="-1">Runtime Changes <a class="header-anchor" href="#runtime-changes" aria-label="Permalink to &quot;Runtime Changes&quot;">​</a></h3><ul><li>Minimum macOS version raised to 12.0</li><li>io_uring poller available on Linux 5.1+</li></ul><h2 id="long-term-roadmap" tabindex="-1">Long-Term Roadmap <a class="header-anchor" href="#long-term-roadmap" aria-label="Permalink to &quot;Long-Term Roadmap&quot;">​</a></h2><h3 id="v0-3-target-q3-2026" tabindex="-1">v0.3 (Target: Q3 2026) <a class="header-anchor" href="#v0-3-target-q3-2026" aria-label="Permalink to &quot;v0.3 (Target: Q3 2026)&quot;">​</a></h3><ul><li>Stabilize <code>graph fn</code> and Metal/CUDA backends</li><li>Complete <code>select {}</code> for channels</li><li>Package manager registry MVP</li></ul><h3 id="v0-4-target-q4-2026" tabindex="-1">v0.4 (Target: Q4 2026) <a class="header-anchor" href="#v0-4-target-q4-2026" aria-label="Permalink to &quot;v0.4 (Target: Q4 2026)&quot;">​</a></h3><ul><li>WASM target stabilization</li><li>LSP: code actions and refactoring</li><li><code>vex bench</code> stabilization</li></ul><h3 id="v1-0-target-2027" tabindex="-1">v1.0 (Target: 2027) <a class="header-anchor" href="#v1-0-target-2027" aria-label="Permalink to &quot;v1.0 (Target: 2027)&quot;">​</a></h3><ul><li>All Tier 1 and Tier 2 features stable</li><li>Backward compatibility guarantees begin</li><li>LTS release cycle established</li></ul><h2 id="reporting-breaking-changes" tabindex="-1">Reporting Breaking Changes <a class="header-anchor" href="#reporting-breaking-changes" aria-label="Permalink to &quot;Reporting Breaking Changes&quot;">​</a></h2><p>If a compiler update breaks your code, check:</p><ol><li>The <a href="https://github.com/meftunca/vex/blob/main/CHANGELOG.md" target="_blank" rel="noreferrer">CHANGELOG.md</a> for documented changes</li><li>Whether you were using Tier 3/4 features (experimental -- changes expected)</li><li>File an issue at <a href="https://github.com/meftunca/vex/issues" target="_blank" rel="noreferrer">github.com/meftunca/vex/issues</a></li></ol><h2 id="best-practices" tabindex="-1">Best Practices <a class="header-anchor" href="#best-practices" aria-label="Permalink to &quot;Best Practices&quot;">​</a></h2><ol><li>Pin Vex version in CI (<code>vex --version</code> in build scripts).</li><li>Avoid Tier 4 (internal) APIs -- they WILL break.</li><li>Isolate Tier 3 (experimental) usage behind feature flags for easy removal.</li><li>Check the changelog before upgrading Vex versions.</li><li>Use <code>#[deprecated]</code> in your own libraries for graceful API evolution.</li></ol>`,44)])])}const u=a(n,[["render",r]]);export{g as __pageData,u as default};
